mapper.select:
 SELECT id, type, amount, category_name, merchant_name, occurred_at, ocr_task_id AS source
 FROM transactions
WHERE user_id = #{userId}
   AND status = 0

       AND occurred_at >= #{startTime}


       AND occurred_at <= #{endTime}


       AND type = #{type}


       AND category_name = #{categoryName}

 ORDER BY occurred_at DESC

SELECT
DATE_FORMAT(occurred_at, '%Y-%m-%d') AS date,
SUM(CASE WHEN type = 0 THEN amount ELSE 0 END) AS expenseTotal,
SUM(CASE WHEN type = 1 THEN amount ELSE 0 END) AS incomeTotal
FROM transactions
WHERE user_id = #{userId}
AND status = 0

    AND occurred_at >= #{startTime}


    AND occurred_at <= #{endTime}


    AND category_name = #{categoryName}

GROUP BY DATE_FORMAT(occurred_at, '%Y-%m-%d')
ORDER BY date DESC

SELECT
category_name AS categoryName,
SUM(amount) AS totalAmount
FROM transactions
WHERE user_id = #{userId}
AND status = 0


    AND occurred_at >= #{startTime}


    AND occurred_at  <=#{endTime}


    AND type = #{type}


GROUP BY category_name

SELECT
    SUM(CASE WHEN type = 0 THEN amount ELSE 0 END) AS expenseTotal,
    SUM(CASE WHEN type = 1 THEN amount ELSE 0 END) AS incomeTotal
FROM transactions
WHERE user_id = #{userId}
  AND status = 0
  AND occurred_at >= #{startTime}
  AND occurred_at <= #{endTime}
